 */
inline void relu(std::vector<double> &x) {
    const std::size_t n = x.size();

    /* OpenMP block ensures granularity > 1*/
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        double v = x[i];
        /* explicit comparison preserves NaN handling of std::max */
        x[i] = (v > 0.0) ? v : 0.0;
    }
}
