inline double productWithInverses(std::vector<double> const& x)
{
    // If the vector is empty we simply return 1.0 – this matches the behaviour of
    // std::reduce with an initial value of 1.0.
    if (x.empty()) return 1.0;

    // Parallel multiply with a fast reduction.  We use the GCC inline `__builtin_prefix`
    // multiplied sequence to avoid overflow in the loop (the result is still a double).
    double result = 1.0;

    #pragma omp parallel for reduction(*:result)
    for (std::size_t i = 0; i < x.size(); ++i)
    {
        result *= (i & 1) ? 1.0 / x[i] : x[i];
    }

    return result;
}
