inline void negateOddsAndHalveEvens(std::vector<int> &x) {
    const std::size_t N = x.size();

    /* Parallelize with OpenMP; static schedule gives good load balance
       and uses loop‑independent iterations. */
    #pragma omp parallel for schedule(static)
    for (std::size_t idx = 0; idx < N; ++idx) {
        int v = x[idx];
        /* Branchless implementation:
           - if v odd (v & 1): negate
           - else: halve (integer division truncates toward 0 for positives
             and negatives, which matches the original behaviour). */
        x[idx] = (v & 1) ? -v : v / 2;
    }
}
