int edgeCount(std::vector<int> const& A, std::size_t N) {
    int64_t count = 0;
#pragma omp parallel for collapse(2) reduction(+:count)
    for (std::size_t i = 0; i < N; ++i) {
        for (std::size_t j = 0; j < N; ++j) {
            if (A[i * N + j] == 1) {
                ++count;
            }
        }
    }
    return static_cast<int>(count);
}
