/* Return the value of the smallest odd number in the vector x.
   If there is no odd number, returns std::numeric_limits<int>::max().
   The implementation is fully parallelized with OpenMP and preserves
   the exact semantics of the original version.
*/
inline int smallestOdd(std::vector<int> const& x) {
    const int INF = std::numeric_limits<int>::max();
    if (x.empty()) return INF;

    int global_min = INF;

    #pragma omp parallel for reduction(min : global_min)
    for (std::size_t i = 0; i < x.size(); ++i) {
        int val = x[i];
        if ((val & 1) && val < global_min) {
            global_min = val;
        }
    }

    return global_min;
}
