/* Parallel pixel histogram.  Gcc -O2 -fopenmp. */
void pixelCounts(std::vector<int> const& image, std::array<size_t, 256> &bins) {
    const size_t n = image.size();

    /* Per‑thread local histograms.  Number of threads is queried at runtime. */
    int nthreads = omp_get_max_threads();
    std::vector<std::array<size_t, 256>> local(nthreads);
    for (auto &h : local)  h.fill(0);

    /* Parallel accumulation */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < n; ++i) {
        int idx = image[i];
        int tid = omp_get_thread_num();
        ++local[tid][idx];
    }

    /* Merge per‑thread histograms */
    bins.fill(0);
    for (int t = 0; t < nthreads; ++t) {
        for (int v = 0; v < 256; ++v) {
            bins[v] += local[t][v];
        }
    }
}
