#pragma once
#include <vector>
#include <algorithm>
#include <omp.h>

/*
 * Compute the maximum node degree in an undirected graph represented
 * by a flat NxN adjacency matrix `A` (row-major order).
 *
 * Parameters
 * ----------
 * A : const std::vector<int>&
 *     Flattened adjacency matrix.
 * N : size_t
 *     Dimension of the matrix (number of vertices).
 *
 * Returns
 * -------
 * int
 *     Highest vertex degree found in the graph.
 */
inline int maxDegree(const std::vector<int> &A, size_t N) {
    int highestDegree = 0;

    /* Parallelize the outer loop over rows.
     * The inner sum is naturally O(N) and the reduction on the
     * maximum can be performed across threads efficiently.
     */
    #pragma omp parallel for reduction(max : highestDegree)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        int degree = 0;
        const int* row = &A[i * N];
        for (int j = 0; j < static_cast<int>(N); ++j) {
            degree += row[j];
        }
        if (degree > highestDegree) {
            highestDegree = degree;
        }
    }

    return highestDegree;
}
