#include <execution>

#if defined(_MSC_VER) && !defined(_OPENMP)
#include <omp.h>               // use OpenMP if available on MSVC
#endif

/* Compute the prefix sum of the vector `x` into `output` in
   O(n) time with parallel execution. The output vector must
   be big enough to receive the result. */
inline void prefixSum(const std::vector<int64_t>& x, std::vector<int64_t>& output) {
    // Ensure the output vector is the correct size.
    if (output.size() < x.size())
        output.resize(x.size());

#if defined(__cpp_execution) && __cpp_execution >= 201309L
    // Use the C++17 parallel execution policy if available.
    std::inclusive_scan(std::execution::par_unseq, x.begin(), x.end(), output.begin());
#else
    // Fallback to OpenMP parallel inclusive scan.
    #pragma omp parallel for
    for (std::size_t i = 0; i < x.size(); ++i) {
        int64_t sum = 0;
        for (std::size_t j = 0; j <= i; ++j)
            sum += x[j];
        output[i] = sum;
    }
#endif
}
