inline void countQuartiles(std::vector<double> const& x, std::array<std::size_t, 4> &bins) {
    // Zero the output bins first
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Per‑thread accumulators to avoid atomic operations
    std::vector< std::array<std::size_t, 4> > thread_bins(omp_get_max_threads());
    for (auto &b : thread_bins) b.fill(0);

    #pragma omp parallel
    {
        int const tid = omp_get_thread_num();
        auto &b = thread_bins[tid];
        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < x.size(); ++i) {
            double const val  = x[i];
            double const frac = val - std::floor(val);          // exact fractional part
            if (frac < 0.25)      ++b[0];
            else if (frac < 0.5)  ++b[1];
            else if (frac < 0.75) ++b[2];
            else                  ++b[3];
        }
    }

    // Reduce per‑thread results into the final output
    for (auto const& b : thread_bins) {
        bins[0] += b[0];
        bins[1] += b[1];
        bins[2] += b[2];
        bins[3] += b[3];
    }
