27_reduce_average:
```cpp
// optimized_average.hpp
#pragma once
#include <vector>
#include <cstddef>
#include <cstdint>
#include <limits>
#include <omp.h>

/* Return the average of the vector x.
   Examples:
   input: [1, 8, 4, 5, 1]
   output: 3.8
   input: [2, 2, 2, 3]
   output: 2.25
   The function preserves the exact behavior of the reference
   implementation (including division by zero on an empty vector).
*/
inline double average(std::vector<double> const& x) noexcept {
    const std::size_t n = x.size();
    if (n == 0) {
        // Mimic the reference implementation: 0 / 0 == NaN (or inf on some platforms)
        return std::numeric_limits<double>::quiet_NaN();
    }

    double sum = 0.0;
    // Parallel sum with OpenMP; use a careful reduction to avoid
    // any enclave data races.  The default schedule is best for
    // small to medium vectors; for very large vectors an explicit
    // schedule(static) might be better, but we leave it to auto‑tune.
#pragma omp parallel for reduction(+:sum)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n); ++i) {
        sum += x[static_cast<std::size_t>(i)];
    }

    return sum / static_cast<double>(n);
}
