/* Count the number of cartesian points in each quadrant.
   The vector points contains a list of `Point` objects.
   Store the counts in `bins`.
   Example:
   input: [{x=1.5, y=0.1}, {x=-3, y=1.1}, {x=5, y=9},
           {x=1.5, y=-1}, {x=3, y=-7}, {x=0.1, y=2}]
   output: [3, 1, 0, 2]
*/
void countQuadrants(std::vector<Point> const& points,
                    std::array<std::size_t, 4> &bins)
{
    // Reset output bins
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Note: using an array of uint64_t for reduction guarantees atomicity on 64‑bit
    // architectures.  The OpenMP reduction clause is used for thread‑level
    // parallelism, which is more efficient than a lock or atomic increments per
    // point.
    #pragma omp parallel for reduction(+:bins[0], bins[1], bins[2], bins[3])
    for (std::size_t i = 0; i < points.size(); ++i) {
        const Point &p = points[i];
        if (p.x >= 0.0) {
            if (p.y >= 0.0) {
                ++bins[0];
            } else {
                ++bins[3];
            }
        } else {
            if (p.y >= 0.0) {
                ++bins[1];
            } else {
                ++bins[2];
            }
        }
    }
}
