#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct Element {
    std::size_t index;
    double value;
};

/* 
 * Compute z = alpha*x + y where x and y are sparse vectors.
 * The result is stored in the dense vector z.
 *
 * The function is pure and thread‑safe – the interior algorithm is
 * parallelized using OpenMP.  Each element is added to the output
 * vector via an atomic += to preserve the exact semantics of the
 * sequential implementation.
 */
void sparseAxpy(double alpha, const std::vector<Element>& x,
                const std::vector<Element>& y,
                std::vector<double>& z)
{
    // Update z with contributions from x
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i) {
        const std::size_t idx = x[i].index;
        const double val   = alpha * x[i].value;
        #pragma omp atomic
        z[idx] += val;
    }

    // Update z with contributions from y
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i) {
        const std::size_t idx = y[i].index;
        const double val   = y[i].value;
        #pragma omp atomic
        z[idx] += val;
    }
}
