#pragma once
#include <vector>
#include <unordered_map>
#include <cstddef>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/* SpMM: Y = A * X
 *   A : sparse MxK matrix in COO
 *   X : sparse KxN matrix in COO
 *   Y : dense MxN matrix (row‑major)
 * This implementation builds a hash table for X and uses OpenMP
 * to parallelise over the rows of A.  Each thread updates `Y` with
 * atomic additions to avoid race conditions.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N)
{
    Y.assign(M * N, 0.0);

    /* Build row → list of (col, value) for X.  Using an array of
     * unordered_maps for cache friendliness.  This structure is
     * read‑only after construction, so no lock is needed. */
    std::vector<std::unordered_map<size_t, double>> x_rows(K);
    for (auto const& e : X) {
        x_rows[e.row][e.column] = e.value;
    }

    /* Parallel multiplication over the non‑zero entries of A.
     * Each iteration updates one or more elements of Y; atomic
     * adds serialize updates to the same memory location. */
    #pragma omp parallel for schedule(dynamic, 256)
    for (int ia = 0; ia < static_cast<int>(A.size()); ++ia) {
        const auto& a = A[ia];
        auto const& row_map = x_rows[a.column];
        for (auto const& [col, xv] : row_map) {
            size_t idx = a.row * N + col;
            #pragma omp atomic
            Y[idx] += a.value * xv;
        }
    }
}
