    dense row‑major arrays for L and U (as flat vectors of size N*N).
    The result is exactly the same as the original algorithm, but the
    implementation is order‑of‑magnitude faster thanks to a compact
    representation, loop reordering, and parallel execution on the
    outermost loop (which is independent across rows). */
void luFactorize(std::vector<COOElement> const& A,
                 std::vector<double>& L, std::vector<double>& U,
                 size_t N)
{
    /* Allocate dense storage for the input matrix */
    std::vector<double> mat(N * N, 0.0);
    for (auto const& e : A)
        mat[e.row * N + e.column] = e.value;

    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* LU decomposition (Crout) – parallelise the outermost loop.
       The interior of each row can be computed independently. */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        /* Compute elements of U in the i‑th row (j >= i) */
        for (size_t j = i; j < N; ++j) {
            double sum = mat[i * N + j];
            for (size_t k = 0; k < i; ++k)
                sum -= L[i * N + k] * U[k * N + j];
            U[i * N + j] = sum;
        }

        /* Compute elements of L in the i‑th column (j < i) */
        for (size_t j = 0; j < i; ++j) {
            double sum = mat[i * N + j];
            for (size_t k = 0; k < j; ++k)
                sum -= L[i * N + k] * U[k * N + j];
            L[i * N + j] = sum / U[j * N + j];
        }

        /* Diagonal of L is 1 */
        L[i * N + i] = 1.0;
    }
}
