/* Disjoint Set (Union‑Find) implementation */
struct DSU {
    std::vector<std::size_t> parent, rank;
    DSU(std::size_t n) : parent(n), rank(n, 0) {
        for (std::size_t i = 0; i < n; ++i) parent[i] = i;
    }
    std::size_t find(std::size_t x) {
        while (x != parent[x]) {
            parent[x] = parent[parent[x]];  // path compression
            x = parent[x];
        }
        return x;
    }
    void unite(std::size_t a, std::size_t b) {
        std::size_t ra = find(a), rb = find(b);
        if (ra == rb) return;
        if (rank[ra] < rank[rb]) std::swap(ra, rb);
        parent[rb] = ra;
        if (rank[ra] == rank[rb]) ++rank[ra];
    }
};

/* Count the number of connected components in the undirected graph defined by
   the adjacency matrix A (row‑major). Complexity: O(N²) with minimal overhead. */
int componentCount(std::vector<int> const& A, std::size_t N) {
    if (N == 0) return 0;

    DSU dsu(N);

    /* Union all edges. Since the graph is undirected, only the upper triangle
       needs to be processed to avoid duplicate work. */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t base = i * N;
        for (std::size_t j = i + 1; j < N; ++j) {
            if (A[base + j]) dsu.unite(i, j);
        }
    }

    /* Count distinct roots. */
    std::size_t comps = 0;
    for (std::size_t i = 0; i < N; ++i) {
        if (dsu.find(i) == i) ++comps;
    }
    return static_cast<int>(comps);
}
