/* Compute one iteration of a 3-point 1D jacobi stencil on `input`. Store the results in `output`.
   Each element of `input` will be averaged with its two neighbors and stored in the corresponding element of `output`.
   i.e. output[i] = (input[i-1]+input[i]+input[i+1])/3
   Replace missing neighbors with 0 when reading past the boundaries of `input`.
*/
inline void jacobi1D(std::vector<double> const& input, std::vector<double> &output) {
    const std::size_t n = input.size();
    if (n == 0) return;

    // Ensure output has the correct size
    if (output.size() != n) output.resize(n);

    const double div3 = 1.0 / 3.0;
    const double *in = input.data();
    double *out = output.data();

#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        double sum = in[i];
        if (i > 0)    sum += in[i - 1];
        if (i + 1 < n) sum += in[i + 1];
        out[i] = sum * div3;
    }
}
