/* Compute the prefix sum array of the vector x and return its sum.
   Example:
   input: [-7, 2, 1, 9, 4, 8]
   output: 15
*/
int64_t sumOfPrefixSum(const std::vector<int64_t>& x) {
    const size_t n = x.size();
    std::vector<int64_t> prefixSum(n);

    if (n == 0) return 0;

    // Determine grain size (chunk size)
    const size_t num_threads = omp_get_max_threads();
    const size_t chunk = std::max<size_t>(2, n / (num_threads * 2));

    std::vector<int64_t> blockSums(num_threads + 1, 0);

    // 1. Compute local prefix sums for each chunk
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        size_t start = tid * chunk;
        size_t end   = std::min(start + chunk, n);

        if (start < end) {
            int64_t sum = 0;
            for (size_t i = start; i < end; ++i) {
                sum += x[i];
                prefixSum[i] = sum;
            }
            blockSums[tid + 1] = sum; // store local total
        }
    }

    // 2. Compute cumulative sums of blockSums to obtain offsets
    for (size_t i = 1; i <= num_threads; ++i)
        blockSums[i] += blockSums[i - 1];

    // 3. Add offsets to each chunk (parallel again)
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        size_t start = tid * chunk;
        size_t end   = std::min(start + chunk, n);
        int64_t offset = blockSums[tid];

        if (start < end) {
            for (size_t i = start; i < end; ++i)
                prefixSum[i] += offset;
        }
    }

    // 4. Sum the prefixSum array (parallel reduction)
    int64_t total = 0;
    #pragma omp parallel for reduction(+:total)
    for (size_t i = 0; i < n; ++i)
        total += prefixSum[i];

    return total;
}
