#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <algorithm>
#include <numeric>
#include <omp.h>

/* Fast iterative Cooley–Tukey radix‑2 FFT.
   The routine keeps the same observable behaviour as the original,
   entirely in-place except for the array that holds the input.
   Results are written into the provided output vectors `r` and `i`. */
void fft(std::vector<std::complex<double>> const& x,
         std::vector<double> &r,
         std::vector<double> &i)
{
    const size_t N = x.size();
    if (N == 0) return;

    // first copy the data into a working buffer
    std::vector<std::complex<double>> buf(x);

    // ---------- 1. Bit‑reversal permutation ----------
    // compute the position of the bit–reversed index for every j
    size_t m = static_cast<size_t>(std::log2(N));
    std::vector<size_t> rev(N);
    rev[0] = 0;
    for (size_t j = 1; j < N; ++j) {
        rev[j] = (rev[j >> 1] >> 1) | ((j & 1) << (m - 1));
    }

    // reorder the buffer in parallel
    #pragma omp parallel for schedule(static)
    for (size_t j = 0; j < N; ++j) {
        if (rev[j] > j) {
            std::swap(buf[j], buf[rev[j]]);
        }
    }

    // ---------- 2. Butterfly stages ----------
    const double PI = acosl(-1.0);
    for (size_t s = 1, len = 2; len <= N; s++, len <<= 1) {
        const double theta = -2.0 * PI / (double)len;
        const std::complex<double> wlen(std::cos(theta), std::sin(theta));

        // We can parallelise the outer loop over the blocks
        #pragma omp parallel for schedule(static)
        for (size_t k = 0; k < N; k += len) {
            std::complex<double> w(1.0, 0.0);
            for (size_t j = 0; j < len / 2; ++j) {
                std::complex<double> u = buf[k + j];
                std::complex<double> t = w * buf[k + j + len / 2];
                buf[k + j]            = u + t;
                buf[k + j + len / 2]  = u - t;
                w *= wlen;
            }
        }
    }

    // ---------- 3. Output ----------
    // copy real / imaginary parts into the output vectors
    r.resize(N);
    i.resize(N);
    #pragma omp parallel for schedule(static)
    for (size_t j = 0; j < N; ++j) {
        r[j] = buf[j].real();
        i[j] = buf[j].imag();
    }
}
