#pragma once
#include <vector>
#include <cstdint>
#include <algorithm>

/*
   Return the number of vertices in the largest component of the graph
   defined by the adjacency matrix A.  A is an NxN adjacency matrix
   stored in row‑major order.
*/
int largestComponent(const std::vector<int>& A, size_t N)
{
    // use a byte per vertex instead of std::vector<bool>
    std::vector<uint8_t> visited(N, 0);

    int largest = 0;
    std::vector<int> stack;
    stack.reserve(N);                     // avoid reallocations

    for (int start = 0; start < static_cast<int>(N); ++start)
    {
        if (visited[start]) continue;

        int count = 0;
        stack.clear();
        stack.push_back(start);
        visited[start] = 1;

        while (!stack.empty())
        {
            int u = stack.back();
            stack.pop_back();
            ++count;

            const int* row = &A[u * N];
            for (int v = 0; v < static_cast<int>(N); ++v)
            {
                if (row[v] && !visited[v])
                {
                    visited[v] = 1;
                    stack.push_back(v);
                }
            }
        }
        largest = std::max(largest, count);
    }
    return largest;
}
