#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Compute the reverse prefix sum of the vector x into output.
   Examples:
   input:  [1, 7, 4, 6, 6, 2]
   output: [2, 8, 14, 18, 25, 26]
   input:  [3, 3, 7, 1, -2]
   output: [-2, -1, 6, 9, 12]
*/
inline void reversePrefixSum(const std::vector<int>& x, std::vector<int>& output) {
    const std::size_t n = x.size();
    output.resize(n);
    if (n == 0) return;

    /* 1. break the work into blocks and compute partial inclusive scans
       in parallel.  Each block writes its results into the corresponding
       positions of the output vector and records the block’s total sum.    */
    const std::size_t blockSize = 1024;           // tuned for typical cache size
    const std::size_t blockCnt  = (n + blockSize - 1) / blockSize;
    std::vector<int> blockSums(blockCnt);

    #pragma omp parallel for schedule(static)
    for (std::size_t b = 0; b < blockCnt; ++b) {
        std::size_t start = b * blockSize;
        std::size_t end   = start + blockSize;
        if (end > n) end = n;
        int sum = 0;
        for (std::size_t i = end; i-- > start; ) { // reverse loop
            sum += x[i];
            output[i] = sum;
        }
        blockSums[b] = sum;
    }

    /* 2. compute the prefix of the block sums so that we can adjust each
       block’s results by the sums of all previous blocks.                                         */
    int blockPrefix = 0;
    for (std::size_t b = 0; b < blockCnt; ++b) {
        int cur = blockSums[b];
        blockSums[b] = blockPrefix;
        blockPrefix += cur;
    }

    /* 3. add the corresponding block prefix to each element in the block.                */
    #pragma omp parallel for schedule(static)
    for (std::size_t b = 0; b < blockCnt; ++b) {
        std::size_t start = b * blockSize;
        std::size_t end   = start + blockSize;
        if (end > n) end = n;
        int add = blockSums[b];
        for (std::size_t i = start; i < end; ++i) {
            output[i] += add;
        }
    }
}
