/* Return the distance between the closest two elements in the vector x.
   Example:
   input: [7, 3, 9, 12, 31, 1]
   output: 2
*/
double closestPair(std::vector<double> const& x) {
    // The vector needs to have at least two elements
    if (x.size() < 2) {
        return 0.0;
    }

    // Make a copy and sort it – O(n log n) but much faster than the O(n²)
    // pairwise comparison for realistic input sizes.
    std::vector<double> v(x.begin(), x.end());
    std::sort(v.begin(), v.end());

    // Minimum distance will be between adjacent elements in the sorted array.
    double minDist = std::numeric_limits<double>::max();

    // Parallel reduction to find the smallest adjacent difference.
    #pragma omp parallel for reduction(min:minDist)
    for (std::size_t i = 1; i < v.size(); ++i) {
        double d = v[i] - v[i - 1];   // v is sorted, so abs not needed
        if (d < minDist) {
            minDist = d;
        }
    }
    return minDist;
}
