        const bool has_below = (i + 1 < N);
        for (size_t j = 0; j < N; ++j) {
            int count = 0;

            // Count the '1's among the four orthogonal neighbours
            if (has_above && in[(i-1)*N + j] == 1) ++count;
            if (has_below && in[(i+1)*N + j] == 1) ++count;
            if (j > 0     && in[row_offset + j - 1] == 1) ++count;
            if (j + 1 < N && in[row_offset + j + 1] == 1) ++count;

            out[row_offset + j] = (count == 1) ? 1 : 0;
        }
    }
}
