#pragma once
#include <array>
#include <vector>
#include <cstddef>
#include <cstring>   // for memset
#include <omp.h>     // OpenMP

// Count how many values fall into each 10‑wide bin between 0 and 100.
// Assumes every element in `x` is between 0 and 100 inclusive.
// `bins` must be size 10 and should contain zeroes before the call.
inline void binsBy10Count(std::vector<double> const& x, std::array<std::size_t, 10>& bins)
{
    // Ensure the output array starts zeroed
    std::memset(bins.data(), 0, bins.size() * sizeof(std::size_t));

    // Use an array reduction if the compiler supports it; otherwise
    // fall back to thread‑local bins plus a critical merge step.
    // GCC supports array reductions with the `[:N]` syntax.
#if defined(__GNUC__) && (!defined(__INTEL_COMPILER) || __INTEL_COMPILER < 19)
#   pragma omp parallel for schedule(static) reduction(+:bins[:10])
    for (std::size_t i = 0; i < x.size(); ++i)
    {
        // Using integer division of the double value is safe; values
        // are guaranteed to be in [0,100], so the index is in [0,10].
        std::size_t bin = static_cast<std::size_t>(x[i] / 10.0);
        // Clamp in case of rounding errors that might give 10.
        if (bin >= 10) bin = 9;
        ++bins[bin];
    }
#else
    // Fallback to thread‑local bins when array reduction isn't available.
    const int n_threads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 10>> local_bins(n_threads);
#pragma omp parallel
    {
        int tid = omp_get_thread_num();
        auto& local = local_bins[tid];
        std::memset(local.data(), 0, local.size() * sizeof(std::size_t));

#   pragma omp for schedule(static)
        for (std::size_t i = 0; i < x.size(); ++i)
        {
            std::size_t bin = static_cast<std::size_t>(x[i] / 10.0);
            if (bin >= 10) bin = 9;  // defensive clamp
            ++local[bin];
        }
    }
    // Reduce local bins into the result
    for (int t = 0; t < n_threads; ++t)
    {
        for (std::size_t b = 0; b < 10; ++b)
            bins[b] += local_bins[t][b];
    }
#endif
}
```
This implementation:

* Zeroes `bins` at entry to guarantee deterministic output.
* Uses GCC’s array reduction (`reduction(+:bins[:10])`) for maximum parallelism.
* Provides a portable fallback that accumulates per‑thread local arrays and merges them after the loop.
* Clamps the bin index to `9` to guard against any floating point rounding that might produce `10`.

