#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>
#include <numeric>

struct Point
{
    double x, y;
};

/*
  Convex hull via monotone chain.
  Time: O(n log n).  Memory: O(n).
*/
inline double cross(const Point& a, const Point& b, const Point& c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(std::vector<Point> const& points, std::vector<Point>& hull)
{
    size_t n = points.size();
    if (n < 3) {
        hull = points;          // preserve original order
        return;
    }

    // Make a copy for sorting
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b)
              {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    hull.clear();
    hull.reserve(2 * n);          // upper bound

    // Build lower hull
    for (size_t i = 0; i < n; ++i)
    {
        while (hull.size() >= 2 &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], sorted[i]) <= 0)
            hull.pop_back();
        hull.push_back(sorted[i]);
    }

    // Build upper hull
    size_t lowerSize = hull.size();
    for (size_t i = n - 1; i > 0; --i)
    {
        while (hull.size() > lowerSize &&
               cross(hull[hull.size() - 2], hull[hull.size() - 1], sorted[i - 1]) <= 0)
            hull.pop_back();
        hull.push_back(sorted[i - 1]);
    }

    // Remove duplicate last point
    hull.pop_back();
}
