#pragma once
#include <vector>
#include <cmath>
#include <complex>
#include <algorithm>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.141592653589793238462643383279502884
#endif

// ---------------------------------------------------------------
// Optimised Cooley–Tukey radix‑2 FFT (single‑precision)
// ---------------------------------------------------------------
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<std::complex<double>>& output)
{
    const size_t N = x.size();
    const size_t logN = static_cast<size_t>(std::log2(N));
    if (N == 0)    { output.clear(); return; }
    if (N & (N-1)) // Not a power of two
        throw std::invalid_argument("fft(): length must be a power of 2");

    output.resize(N);
    std::copy(x.begin(), x.end(), output.begin());

    // ----- Pre‑compute twiddle factors -----
    std::vector<std::complex<double>> twiddles(N/2);
    const double angle = -M_PI / (N/2);
    double real = 1.0, imag = 0.0;
    std::complex<double> w = std::exp(std::complex<double>(0.0, angle));
    for (size_t i = 0; i < N/2; ++i) {
        twiddles[i] = std::complex<double>(real, imag);
        // Multiply by w
        double r = real*w.real() - imag*w.imag();
        double g = real*w.imag() + imag*w.real();
        real = r; imag = g;
    }

    // ----- Bit reversed index lookup table -----
    std::vector<size_t> rev(N);
    rev[0] = 0;
    for (size_t i = 1; i < N; ++i) {
        rev[i] = (rev[i>>1] >> 1) | ((i & 1) << (logN-1));
    }

    // ----- FFT stages -----
    const size_t halfN = N / 2;
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < halfN; ++i) {
        size_t j = rev[i] >> 1;
        if (j > i) {
            std::swap(output[i], output[j]);
        }
    }

    size_t step = 1;
    for (size_t stage = 0; stage < logN; ++stage, step <<= 1) {
        size_t twiddle_step = N / (step << 1);
        #pragma omp parallel for schedule(static)
        for (size_t group = 0; group < step; ++group) {
            const std::complex<double> w = twiddles[group * twiddle_step];
            for (size_t i = group; i < N; i += step << 1) {
                std::complex<double> t = w * output[i + step];
                output[i + step] = output[i] - t;
                output[i] += t;
            }
        }
    }
}
