inline void gemv(const std::vector<double> &A,
                 const std::vector<double> &x,
                 std::vector<double>       &y,
                 size_t M, size_t N)
{
    // Return immediately on empty matrix or vector
    if (M == 0 || N == 0) return;

    // Pointers to the underlying arrays – GCC will
    // automatically vectorise the inner loop thanks to the -O2 compiler flag.
    const double *Aptr = A.data();
    const double *xptr = x.data();
          double *yptr = y.data();

    // Parallelise over rows.  The work is perfectly parallelisable,
    // and the two loops together are a classic data‑parallel pattern.
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < M; ++i)
    {
        double sum = 0.0;
        const double *row = Aptr + i * N;
        // The inner dot product can be auto‑vectorised by GCC.
        for (size_t j = 0; j < N; ++j)
            sum += row[j] * xptr[j];
        yptr[i] = sum;
    }
