#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Exact‑behaviour solver for ax=b with a sparse COO matrix.
   The implementation keeps the same algorithmic logic (partial
   pivoting, Gaussian elimination, back‑substitution) but leverages
   OpenMP for parallel inner‑row operations.  The dense matrix
   representation is retained because the input format is COO
   and converting to CSR would change the guarantee that the
   function produces exactly the same numeric result as the
   original (which is agnostic to the storage format).
*/
void solveLinearSystem(const std::vector<COOElement>& A,
                       const std::vector<double>&  b,
                       std::vector<double>&        x,
                       size_t                      N)
{
    /* Allocate a dense matrix with zero initialization */
    std::vector<std::vector<double>> matrix(N, std::vector<double>(N, 0.0));
    std::vector<double> b_copy = b;          // keep a local copy

    /* Fill the dense matrix with the non‑zero entries */
    for (const auto& e : A) {
        matrix[e.row][e.column] = e.value;
    }

    x.assign(N, 0.0);

    /* Gaussian elimination with partial pivoting */
    for (size_t i = 0; i < N; ++i) {
        /* 1. Find pivot row (max absolute value) – parallel reduction */
        size_t maxRow = i;
        double maxEl  = std::abs(matrix[i][i]);

        #pragma omp parallel
        {
            double local_max  = maxEl;
            size_t  local_row = i;

            #pragma omp for nowait
            for (size_t k = i + 1; k < N; ++k) {
                double val = std::abs(matrix[k][i]);
                if (val > local_max) {
                    local_max  = val;
                    local_row  = k;
                }
            }

            #pragma omp critical
            {
                if (local_max > maxEl) {
                    maxEl   = local_max;
                    maxRow  = local_row;
                }
            }
        }

        /* 2. Swap pivot row with current row (column by column) */
        if (maxRow != i) {
            std::swap_ranges(matrix[maxRow].begin() + i,
                             matrix[maxRow].end(),
                             matrix[i].begin() + i);
            std::swap(b_copy[maxRow], b_copy[i]);
        }

        /* 3. Eliminate entries below pivot */
        #pragma omp parallel for schedule(static)
        for (size_t k = i + 1; k < N; ++k) {
            double c = -matrix[k][i] / matrix[i][i];
            if (c == 0.0) continue;  // nothing to do

            /* Each row k is independent – safe to parallelize */
            for (size_t j = i; j < N; ++j) {
                if (i == j) {
                    matrix[k][j] = 0.0;      // explicit zero
                } else {
                    matrix[k][j] += c * matrix[i][j];
                }
            }
            b_copy[k] += c * b_copy[i];
        }
    }

    /* Back–substitution on the upper‑triangular matrix */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        x[i] = b_copy[i] / matrix[i][i];
        for (int k = i - 1; k >= 0; --k) {
            b_copy[k] -= matrix[k][i] * x[i];
        }
    }
}
