#pragma once
#include <vector>
#include <limits>
#include <algorithm>
#include <omp.h>

/* Parallel divide‑and‑conquer maximum subarray.
   Uses the classic “four‑value” per‑chunk approach
   (total sum, best prefix, best suffix, best subarray),
   then combines the results with a reduction that
   merges two adjacent blocks.
   The algorithm is O(n) and parallelisable with OpenMP. */

struct ChunkResult {
    int sum;           // total sum of the chunk
    int best_prefix;   // maximum prefix sum
    int best_suffix;   // maximum suffix sum
    int best_subarray; // maximum subarray sum within the chunk
};

static inline ChunkResult process_chunk(const int* begin, const int* end) {
    ChunkResult res;
    res.sum = 0;
    res.best_prefix = std::numeric_limits<int>::lowest();
    res.best_suffix = std::numeric_limits<int>::lowest();
    res.best_subarray = std::numeric_limits<int>::lowest();

    int current_prefix = 0;
    for (auto it = begin; it != end; ++it) {
        current_prefix += *it;
        res.sum += *it;
        if (current_prefix > res.best_prefix) res.best_prefix = current_prefix;
    }

    int current_suffix = 0;
    for (auto it = end - 1; it >= begin; --it) {
        current_suffix += *it;
        if (current_suffix > res.best_suffix) res.best_suffix = current_suffix;
    }

    // For best subarray we can reuse the same loop as prefix with a running max
    int curr = 0;
    for (auto it = begin; it != end; ++it) {
        curr += *it;
        if (curr > res.best_subarray) res.best_subarray = curr;
        if (curr < 0) curr = 0;
    }

    return res;
}

// Merge two adjacent ChunkResult objects into one representing their concatenation
static inline ChunkResult merge(const ChunkResult& left, const ChunkResult& right) {
    ChunkResult res;
    res.sum = left.sum + right.sum;
    res.best_prefix = std::max(left.best_prefix, left.sum + right.best_prefix);
    res.best_suffix = std::max(right.best_suffix, right.sum + left.best_suffix);
    res.best_subarray = std::max({left.best_subarray,
                                  right.best_subarray,
                                  left.best_suffix + right.best_prefix});
    return res;
}

int maximumSubarray(const std::vector<int> &x) {
    if (x.empty()) return 0;  // undefined behaviour in original, but safe fallback

    const int n = static_cast<int>(x.size());
    const int chunks = omp_get_max_threads(); // use as many chunks as threads
    const int chunk_size = (n + chunks - 1) / chunks;

    std::vector<ChunkResult> results(chunks);

    #pragma omp parallel for schedule(static,1)
    for (int k = 0; k < chunks; ++k) {
        int start = k * chunk_size;
        int end = std::min(start + chunk_size, n);
        if (start >= end) {
            results[k] = {0, std::numeric_limits<int>::lowest(),
                          std::numeric_limits<int>::lowest(),
                          std::numeric_limits<int>::lowest()};
            continue;
        }
        results[k] = process_chunk(&x[start], &x[end]);
    }

    // Reduce the chunk results sequentially (cheap, O(threads))
    ChunkResult final_res = results[0];
    for (int k = 1; k < chunks; ++k) {
        if (results[k].best_prefix == std::numeric_limits<int>::lowest() &&
            results[k].best_suffix == std::numeric_limits<int>::lowest() &&
            results[k].best_subarray == std::numeric_limits<int>::lowest())
            continue;
        final_res = merge(final_res, results[k]);
    }

    return final_res.best_subarray;
}
