// lu_factorize_opt.cpp
#pragma once
#include <vector>
#include <omp.h>

inline void luFactorize(std::vector<double> &A, size_t N) {
    double *data = A.data();
    const size_t stride = N;

    // Main LU factorization loop
    for (size_t k = 0; k < N; ++k) {
        const double *row_k = data + k * stride;          // k-th row pointer
        const double ak_k = row_k[k];                    // pivot element

        // Parallel Gaussian elimination for rows i > k
        #pragma omp parallel for schedule(static)
        for (long long li = k + 1; li < static_cast<long long>(N); ++li) {
            long long i = static_cast<size_t>(li);
            double *row_i = data + i * stride;          // i-th row pointer
            double factor = row_i[k] / ak_k;            // L(i,k)
            row_i[k] = factor;                          // store L

            // Update trailing sub-matrix in the i-th row
            double *pj = row_i + k + 1;
            const double *pk = row_k + k + 1;
            size_t len = N - k - 1;
            for (size_t idx = 0; idx < len; ++idx) {
                pj[idx] -= factor * pk[idx];
            }
        }
    }
}
