#include <algorithm>

/*
 * Multiply two matrices:  C = C + A * B
 *   A : M x K   (row-major)
 *   B : K x N   (row-major)
 *   C : M x N   (row-major)
 *
 * The implementation uses a 1‑level cache‑friendly block scheme
 * (block sizes are tuned for an 8‑thread Intel Broadwell‑style CPU).
 * The outermost loop over rows is parallelised with OpenMP.
 * The inner loops are reordered for better temporal locality.
 *
 * The exact algorithmic behaviour (including the accumulation into
 * the existing contents of C) is preserved.
 */

static constexpr size_t BLOCK_M = 64;  // block size for rows of A / C
static constexpr size_t BLOCK_K = 64;  // block size for columns of A / rows of B
static constexpr size_t BLOCK_N = 64;  // block size for columns of B / C

inline void gemm(const std::vector<double> &A,
                 const std::vector<double> &B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    // Parallelise over tiles of rows of A (and C)
    #pragma omp parallel for schedule(static)
    for (size_t i0 = 0; i0 < M; i0 += BLOCK_M) {
        size_t i_max = std::min(i0 + BLOCK_M, M);
        for (size_t k0 = 0; k0 < K; k0 += BLOCK_K) {
            size_t k_max = std::min(k0 + BLOCK_K, K);
            for (size_t j0 = 0; j0 < N; j0 += BLOCK_N) {
                size_t j_max = std::min(j0 + BLOCK_N, N);

                // Compute the sub‑matrix C[i0:i_max , j0:j_max]
                for (size_t i = i0; i < i_max; ++i) {
                    const double* a_row = &A[i * K];
                    double* c_row = &C[i * N + j0];
                    for (size_t k = k0; k < k_max; ++k) {
                        double aik = a_row[k];
                        const double* b_row = &B[k * N + j0];
                        for (size_t j = j0; j < j_max; ++j) {
                            c_row[j - j0] += aik * b_row[j - j0];
                        }
                    }
                }
            }
        }
    }
}
