    // Fast path: scan first vector
    const int* px = x.data();
    const int* ex = px + x.size();
    bool foundX = false;
    for (; px != ex; ++px)
    {
        if (*px == val) { foundX = true; break; }
    }

    // Scan second vector
    const int* py = y.data();
    const int* ey = py + y.size();
    bool foundY = false;
    for (; py != ey; ++py)
