 * The image is stored in row‑major order.
 * The function is fully parallelised with OpenMP and uses
 * hand‑rolled boundary handling for maximum speed.
 */
inline void convolveKernel(
    const std::vector<int> &imageIn,
    std::vector<int> &imageOut,
    size_t N) noexcept
{
    const int *in  = imageIn.data();
    int       *out = imageOut.data();

    /* Parallelise over rows/columns – the cache is
     * naturally split by rows, so we expose a 2‑D
     * parallel loop.  The nested loop is very small,
     * so the overhead is negligible.
     */
#pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        for (size_t j = 0; j < N; ++j) {

            /* Manually unrolled 3×3 convolution. */
            int sum = 0;

            /* Row i-1 */
            if (i > 0) {
                size_t base = (i - 1) * N;

                // Col j-1
                if (j > 0)
                    sum += in[base + (j - 1)] * edgeKernel[0][0];
                // Col j
                sum += in[base + j] * edgeKernel[0][1];
                // Col j+1
                if (j + 1 < N)
                    sum += in[base + (j + 1)] * edgeKernel[0][2];
            }

            /* Row i */
            size_t base = i * N;
            // Col j-1
            if (j > 0)
                sum += in[base + (j - 1)] * edgeKernel[1][0];
            // Col j
            sum += in[base + j] * edgeKernel[1][1];
            // Col j+1
            if (j + 1 < N)
                sum += in[base + (j + 1)] * edgeKernel[1][2];

            /* Row i+1 */
            if (i + 1 < N) {
                base = (i + 1) * N;
                // Col j-1
                if (j > 0)
                    sum += in[base + (j - 1)] * edgeKernel[2][0];
                // Col j
                sum += in[base + j] * edgeKernel[2][1];
                // Col j+1
                if (j + 1 < N)
                    sum += in[base + (j + 1)] * edgeKernel[2][2];
            }

            /* Clip to [0, 255] and store. */
            if (sum < 0)
                out[i * N + j] = 0;
            else if (sum > 255)
                out[i * N + j] = 255;
            else
                out[i * N + j] = sum;
        }
    }
