 *   - the output vector must already be sized N*N.
 *
 * Parallelisation: 2‑D collapse of the outer loops with OpenMP.
 *   - The number of threads is set by the environment variable OMP_NUM_THREADS
 *     (8 threads on the target platform).
 *
 * Performance notes:
 *   - All arithmetic stays in the 32‑bit integer domain.
 *   - Branches are minimal thanks to the logic below.
 *   - Pointer arithmetic replaces repeated computation of indices.
 *   - The outer loops are collapsed to a single large chunk so that each
 *     thread gets a contiguous slice of the grid, improving cache locality.
 */
inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int> &output,
                       size_t N)
{
    const int* in  = input.data();
    int*       out = output.data();

    const size_t stride = N;                 // cells per row
    const size_t total  = N * N;             // total cells

    /* Parallel 2‑D loop: collapse the row and column loops into one.
     * OpenMP will divide the loop into chunks, each thread working on a
     * consecutive block of rows for better cache usage. */
#pragma omp parallel for schedule(static, 1024) collapse(2)
    for (size_t i = 0; i < N; ++i)
    {
        for (size_t j = 0; j < N; ++j)
        {
            const size_t idx = i * stride + j;
            int sum = 0;

            /* Vertical neighbors */
            if (i)         sum += in[idx - stride];   // top
            if (i + 1 < N) sum += in[idx + stride];   // bottom

            /* Horizontal neighbors */
            if (j)         sum += in[idx - 1];       // left
            if (j + 1 < N) sum += in[idx + 1];       // right

            /* Diagonal neighbors */
            if (i && j)           sum += in[idx - stride - 1]; // top‑left
            if (i && j + 1 < N)   sum += in[idx - stride + 1]; // top‑right
            if (i + 1 < N && j)   sum += in[idx + stride - 1]; // bottom‑left
            if (i + 1 < N && j + 1 < N) sum += in[idx + stride + 1]; // bottom‑right

            /* State transition */
            const int cur = in[idx];
            if (cur)
            {
                /* Live cell remains alive with 2 or 3 neighbours */
                out[idx] = (sum == 2 || sum == 3) ? 1 : 0;
            }
            else
            {
                /* Dead cell becomes alive only with exactly 3 neighbours */
                out[idx] = (sum == 3) ? 1 : 0;
            }
        }
    }
}
