/* Return the index of the value in the vector x that is closest to the math constant PI.
   Use M_PI for the value of PI.
   Example:
   input: [9.18, 3.05, 7.24, 11.3, -166.49, 2.1]
   output: 1
*/
size_t findClosestToPi(std::vector<double> const& x) {
    // Small optimisation: use local variables and unroll the loop for speed.
    // The function preserves the exact semantics of the original.
    if (x.empty()) return 0;      // guard against empty input

    const double pi = M_PI;
    const size_t N = x.size();

    size_t bestIdx = 0;
    double bestDiff = std::abs(x[0] - pi);

    // Process blocks of 4 to reduce branch cost (loop‑unrolling)
    std::size_t i = 1;
    const std::size_t unroll = 4;
    const std::size_t limit = N - (N % unroll);

    for (; i < limit; i += unroll) {
        // block 1
        double d0 = std::abs(x[i] - pi);
        if (d0 < bestDiff) { bestDiff = d0; bestIdx = i; }
        // block 2
        double d1 = std::abs(x[i + 1] - pi);
        if (d1 < bestDiff) { bestDiff = d1; bestIdx = i + 1; }
        // block 3
        double d2 = std::abs(x[i + 2] - pi);
        if (d2 < bestDiff) { bestDiff = d2; bestIdx = i + 2; }
        // block 4
        double d3 = std::abs(x[i + 3] - pi);
        if (d3 < bestDiff) { bestDiff = d3; bestIdx = i + 3; }
    }

    // Tail elements
    for (; i < N; ++i) {
        double d = std::abs(x[i] - pi);
        if (d < bestDiff) { bestDiff = d; bestIdx = i; }
    }

    return bestIdx;
