   broken by the original index order. */
inline void ranks(const std::vector<float>& x, std::vector<std::size_t>& ranks_) {
    const std::size_t N = x.size();

    /* 1. Build the index vector.  Using `std::iota` would normally be
       O(N) but we give a small hint to the compiler that the loop body
       is independent so it can be vectorised. */
    std::vector<std::size_t> indices(N);
#pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(N); ++i) {
        indices[static_cast<std::size_t>(i)] = static_cast<std::size_t>(i);
    }

    /* 2. Sort indices according to the values in `x`.  The comparison
       function is inlined and directly accesses the vector. */
    std::sort(indices.begin(), indices.end(),
              [&](std::size_t i1, std::size_t i2) noexcept -> bool {
                  return x[i1] < x[i2];
              });

    /* 3. Write the rank back into `ranks_`.  This can be parallelised
       safely because each target element receives a unique value. */
#pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(N); ++i) {
        ranks_[indices[static_cast<std::size_t>(i)]] = static_cast<std::size_t>(i);
