namespace detail {
    // Pre‑computed twiddle factors table for a maximum N = 2^20 (adjust if needed)
    constexpr std::size_t LIMB_MAX_N = 1 << 20;            // 1,048,576 points
    std::complex<double>* twiddles = nullptr;
    std::size_t twiddles_size = 0;

    void init_twiddles(std::size_t N) {
        if (N <= twiddles_size) return;
        std::size_t new_size = N;
        auto* tmp = new std::complex<double>[new_size];
        double ang = -2.0 * M_PI / static_cast<double>(N);
        for (std::size_t i = 0; i < new_size; ++i)
            tmp[i] = std::exp(std::complex<double>(0, ang * i));
        delete[] twiddles;
        twiddles = tmp;
        twiddles_size = new_size;
    }

    inline std::size_t reverse_bits(std::size_t x, unsigned int log2n) {
        x = (x >> 16) | (x << 16);
        x = ((x & 0xFF00FF00) >> 8) | ((x & 0x00FF00FF) << 8);
        x = ((x & 0xF0F0F0F0) >> 4) | ((x & 0x0F0F0F0F) << 4);
        x = ((x & 0xCCCCCCCC) >> 2) | ((x & 0x33333333) << 2);
        x = ((x & 0xAAAAAAAA) >> 1) | ((x & 0x55555555) << 1);
        return x >> (32 - log2n);
    }
}

// radix‑2 iterative Cooley‐Tukey FFT (in‑place, double precision)
inline void fft_helper(std::vector<std::complex<double>>& x) {
    const std::size_t N = x.size();
    const unsigned int log2n = static_cast<unsigned int>(std::log2(N));
    detail::init_twiddles(N);

    // Bit‑reversal ordering
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = detail::reverse_bits(i, log2n);
        if (j > i) std::swap(x[i], x[j]);
    }

    // Cooley–Tukey
    for (unsigned int s = 1; s <= log2n; ++s) {
        const std::size_t m = 1u << s;          // stage size
        const std::size_t m2 = m >> 1;          // half stage size
        const std::size_t step = N / m;
        const std::complex<double>* w = detail::twiddles; // pre‑computed

        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < m2; ++k) {
            std::complex<double> w_k = w[k * step];
            for (std::size_t j = k; j < N; j += m) {
                std::complex<double> t = w_k * x[j + m2];
                x[j + m2] = x[j] - t;
                x[j] += t;
            }
        }
    }
}

// Inverse FFT wrapper
inline void ifft(std::vector<std::complex<double>>& x) {
    // Conjugate, forward FFT, conjugate, and scale
    std::transform(x.begin(), x.end(), x.begin(),
                   [](auto& v) { return std::conj(v); });
    fft_helper(x);
    std::transform(x.begin(), x.end(), x.begin(),
                   [](auto& v) { return std::conj(v); });
    const double invN = 1.0 / static_cast<double>(x.size());
    #pragma omp parallel for
    for (std::size_t i = 0; i < x.size(); ++i)
        x[i] *= invN;
}
