size_t findFirstEven(std::vector<int> const& x) {
    const size_t N = x.size();
    if (N == 0) return 0;

    size_t best = N;                // fallback index if no even number

    /* Find the first even element in parallel.
       Each thread scans a disjoint chunk and records the
       offset of the first even element it finds (if any).
       The global best index is then updated with the minimum
       seen candidate. */
    #pragma omp parallel
    {
        size_t local_index = N;     // assumes no even found in this chunk
        const size_t chunk = omp_get_num_threads();
        const size_t tid   = omp_get_thread_num();
        const size_t start = tid * N / chunk;
        const size_t end   = (tid + 1) * N / chunk;

        for (size_t i = start; i < end; ++i) {
            if ((x[i] & 1) == 0) {  // faster even test: bitwise AND
                local_index = i;
                break;             // first even in this chunk found
            }
        }

        /* Update the global best index.  Use a critical section
           because each thread is independent and the contention
           is minimal (only once per thread). */
        #pragma omp critical
        {
            if (local_index < best) best = local_index;
        }
    }

    return best;
