struct Point
{
    double x, y;
    bool operator<(Point const& rhs) const
    {
        return x < rhs.x || (x == rhs.x && y < rhs.y);
    }
    bool operator==(Point const& rhs) const
    {
        return x == rhs.x && y == rhs.y;
    }
};

/* 2× area (signed) of triangle (a,b,c) */
inline double area2(Point const& a, Point const& b, Point const& c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/* Convex hull – monotone chain (O(n log n)) */
std::vector<Point> convexHull(std::vector<Point> const& pts)
{
    std::vector<Point> p = pts;
    std::sort(p.begin(), p.end());
    p.erase(std::unique(p.begin(), p.end()), p.end());
    if (p.size() <= 2) return p;

    std::vector<Point> lower, upper;
    lower.reserve(p.size());
    upper.reserve(p.size());

    for (auto const& pt : p)
    {
        while (lower.size() >= 2 &&
               area2(lower[lower.size() - 2], lower.back(), pt) <= 0)
            lower.pop_back();
        lower.push_back(pt);
    }
    for (auto it = p.rbegin(); it != p.rend(); ++it)
    {
        while (upper.size() >= 2 &&
               area2(upper[upper.size() - 2], upper.back(), *it) <= 0)
            upper.pop_back();
        upper.push_back(*it);
    }
    lower.pop_back();
    upper.pop_back();
    lower.insert(lower.end(), upper.begin(), upper.end());
    return lower;
}

/* Minimal area triangle in a convex polygon – O(n^2) rotating calipers */
double smallestArea(std::vector<Point> const& points)
{
    size_t n = points.size();
    if (n < 3) return 0.0;

    // Build convex hull – points are in counter‑clockwise order
    std::vector<Point> hull = convexHull(points);
    n = hull.size();
    if (n < 3) return 0.0;

    double minAreaSq = std::numeric_limits<double>::max();

    /* Parallel outer loop – each thread works on a block of i */
    #pragma omp parallel for schedule(static) reduction(min : minAreaSq)
    for (long long ii = 0; ii < static_cast<long long>(n); ++ii)
    {
        size_t i = static_cast<size_t>(ii);
        size_t k = (i + 2) % n;               // initial third point
        for (size_t j = (i + 1) % n; j != i; j = (j + 1) % n)
        {
            /* Advance k while area increases */
            while (true)
            {
                size_t nk = (k + 1) % n;
                double cur = std::abs(area2(hull[i], hull[j], hull[k]));
                double nxt = std::abs(area2(hull[i], hull[j], hull[nk]));
                if (nxt < cur) break;
                k = nk;
            }
            double ar = std::abs(area2(hull[i], hull[j], hull[k])) * 0.5;
            if (ar < minAreaSq) minAreaSq = ar;
        }
    }
    return minAreaSq;
}
