#include <omp.h>

struct Point {
    double x, y;
};

/* Helper that returns squared distance */
inline double dist2(const Point& a, const Point& b) {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

/* Recursive helper: points are sorted by x.
   ybuf is a temporary buffer to merge by y. */
static double closest_pair_rc(std::vector<Point>& xpts,
                              std::vector<Point>& ybuf,
                              size_t left, size_t right) {
    size_t n = right - left;
    if (n <= 3) {
        double best = std::numeric_limits<double>::max();
        for (size_t i = left; i < right; ++i)
            for (size_t j = i + 1; j < right; ++j)
                best = std::min(best, dist2(xpts[i], xpts[j]));
        /* sort by y for this small range */
        std::sort(xpts.begin() + left, xpts.begin() + right,
                  [](const Point& a, const Point& b){ return a.y < b.y; });
        return best;
    }

    size_t mid = left + n / 2;
    double midx = xpts[mid].x;

    double left_best, right_best;
#pragma omp task shared(xpts, ybuf, left, mid) if (n > 20000) 
    {
        left_best = closest_pair_rc(xpts, ybuf, left, mid);
    }
#pragma omp task shared(xpts, ybuf, mid, right) if (n > 20000) 
    {
        right_best = closest_pair_rc(xpts, ybuf, mid, right);
    }
#pragma omp taskwait
    double d = std::min(left_best, right_best);

    /* Merge by y */
    std::inplace_merge(xpts.begin() + left, xpts.begin() + mid, xpts.begin() + right,
                       [](const Point& a, const Point& b){ return a.y < b.y; });

    /* Build strip */
    std::vector<Point> strip;
    strip.reserve(n);
    double sqrt_d = std::sqrt(d);
    for (size_t i = left; i < right; ++i) {
        if (std::abs(xpts[i].x - midx) < sqrt_d)
            strip.push_back(xpts[i]);
    }

    for (size_t i = 0; i < strip.size(); ++i) {
        for (size_t j = i + 1; j < strip.size() && (strip[j].y - strip[i].y) < sqrt_d; ++j) {
            d = std::min(d, dist2(strip[i], strip[j]));
        }
    }
    return d;
}

/* Public API */
double closestPair(std::vector<Point> const& points) {
    size_t n = points.size();
    if (n < 2) return 0.0;

    std::vector<Point> pts(points);               // make a mutable copy
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b){ return a.x < b.x; });

    std::vector<Point> ybuf(n);
#pragma omp parallel
    {
#pragma omp single nowait
        {
            double min_sq = closest_pair_rc(pts, ybuf, 0, n);
            double result = std::sqrt(min_sq);
            omp_set_lock(&((omp_lock_t){0}));    // dummy to avoid unused warning
            // Store result in outer scope
            #pragma omp critical
            {
                static double final_res;
                final_res = result;
                return final_res;
            }
        }
    }
    /* The return above is within the critical section; the compiler
       will inline it as a return value.  To make the code compilable
       and avoid the warning, we simply compute the result again here: */
    double min_sq = closest_pair_rc(pts, ybuf, 0, n);
    return std::sqrt(min_sq);
